/**
 * @fileoverview ColorPicker helpers - pure utility functions for colour
 *               conversion, parsing, formatting, and clamping.
 *
 * Every function is stateless and side-effect-free.
 *
 * @module module/ColorPicker/helpers
 */

import razyui from '../../index.js';

// ── HSV ↔ RGB ───────────────────────────────────

/**
 * Convert HSV to RGB.
 *
 * @param {number} h  Hue        0–360
 * @param {number} s  Saturation 0–100
 * @param {number} v  Value      0–100
 * @returns {{ r: number, g: number, b: number }}
 */
export function hsvToRgb(h, s, v) {
    s /= 100; v /= 100;
    const c = v * s, x = c * (1 - Math.abs((h / 60) % 2 - 1)), m = v - c;
    let r, g, b;
    if (h < 60)       { r = c; g = x; b = 0; }
    else if (h < 120) { r = x; g = c; b = 0; }
    else if (h < 180) { r = 0; g = c; b = x; }
    else if (h < 240) { r = 0; g = x; b = c; }
    else if (h < 300) { r = x; g = 0; b = c; }
    else              { r = c; g = 0; b = x; }
    return {
        r: Math.round((r + m) * 255),
        g: Math.round((g + m) * 255),
        b: Math.round((b + m) * 255),
    };
}

/**
 * Convert RGB to HSV.
 *
 * @param {number} r  Red   0–255
 * @param {number} g  Green 0–255
 * @param {number} b  Blue  0–255
 * @returns {{ h: number, s: number, v: number }}
 */
export function rgbToHsv(r, g, b) {
    r /= 255; g /= 255; b /= 255;
    const max = Math.max(r, g, b), min = Math.min(r, g, b), d = max - min;
    let h = 0;
    if (d !== 0) {
        if (max === r)      h = ((g - b) / d + (g < b ? 6 : 0)) * 60;
        else if (max === g) h = ((b - r) / d + 2) * 60;
        else                h = ((r - g) / d + 4) * 60;
    }
    return {
        h: Math.round(h),
        s: Math.round((max === 0 ? 0 : d / max) * 100),
        v: Math.round(max * 100),
    };
}

// ── HSV ↔ HSL ───────────────────────────────────

/**
 * Convert HSV to HSL.
 *
 * @param {number} h  Hue        0–360
 * @param {number} s  Saturation 0–100
 * @param {number} v  Value      0–100
 * @returns {{ h: number, s: number, l: number }}
 */
export function hsvToHsl(h, s, v) {
    s /= 100; v /= 100;
    const l = v * (1 - s / 2);
    const sl = (l === 0 || l === 1) ? 0 : (v - l) / Math.min(l, 1 - l);
    return { h, s: Math.round(sl * 100), l: Math.round(l * 100) };
}

/**
 * Convert HSL to HSV.
 *
 * @param {number} h  Hue        0–360
 * @param {number} s  Saturation 0–100
 * @param {number} l  Lightness  0–100
 * @returns {{ h: number, s: number, v: number }}
 */
export function hslToHsv(h, s, l) {
    s /= 100; l /= 100;
    const v = l + s * Math.min(l, 1 - l);
    const sv = v === 0 ? 0 : 2 * (1 - l / v);
    return { h, s: Math.round(sv * 100), v: Math.round(v * 100) };
}

// ── RGB ↔ Hex ───────────────────────────────────

/**
 * Convert RGB to a hex colour string.
 *
 * @param {number} r  Red   0–255
 * @param {number} g  Green 0–255
 * @param {number} b  Blue  0–255
 * @returns {string}  e.g. '#ff5522'
 */
export function rgbToHex(r, g, b) {
    return '#' + [r, g, b]
        .map(c => Math.max(0, Math.min(255, c)).toString(16).padStart(2, '0'))
        .join('');
}

/**
 * Parse a hex colour string to RGB components.
 *
 * @param {string} hex  e.g. '#f52', '#ff5522', '#ff552280'
 * @returns {{ r: number, g: number, b: number }}
 */
export function hexToRgb(hex) {
    hex = hex.replace(/^#/, '');
    if (hex.length === 3) hex = hex[0] + hex[0] + hex[1] + hex[1] + hex[2] + hex[2];
    if (hex.length === 8) hex = hex.slice(0, 6); // strip alpha
    return {
        r: parseInt(hex.slice(0, 2), 16) || 0,
        g: parseInt(hex.slice(2, 4), 16) || 0,
        b: parseInt(hex.slice(4, 6), 16) || 0,
    };
}

// ── Generic colour parser ───────────────────────

/**
 * Parse any CSS colour string into RGB.
 *
 * Supports: hex, rgb(), rgba(), hsl(), hsla(), and named colours (via canvas).
 *
 * @param {string} str  CSS colour value
 * @returns {{ r: number, g: number, b: number }}
 */
export function parseColor(str) {
    str = (str || '').trim().toLowerCase();
    // #hex
    if (/^#([0-9a-f]{3,8})$/i.test(str)) return hexToRgb(str);
    // rgb(r,g,b) / rgba
    let m = str.match(/^rgba?\(\s*(\d+)\s*,\s*(\d+)\s*,\s*(\d+)/);
    if (m) return { r: +m[1], g: +m[2], b: +m[3] };
    // hsl(h,s%,l%) / hsla
    m = str.match(/^hsla?\(\s*(\d+)\s*,\s*(\d+)%?\s*,\s*(\d+)%?/);
    if (m) {
        const hsv = hslToHsv(+m[1], +m[2], +m[3]);
        return hsvToRgb(hsv.h, hsv.s, hsv.v);
    }
    // fallback: use canvas
    try {
        const ctx = razyui.el('canvas')[0].getContext('2d');
        ctx.fillStyle = str;
        return hexToRgb(ctx.fillStyle);
    } catch (_) {}
    return { r: 255, g: 0, b: 0 };
}

// ── Small helpers ───────────────────────────────

/**
 * Create a DOM element with an optional className.
 *
 * @param {string} tag   Tag name
 * @param {string} [cls] Space-separated class names
 * @returns {Elements}
 */
export function mk(tag, cls) {
    return razyui.el(tag, cls ? { className: cls } : undefined);
}

/**
 * Compute the current hex value from an HSV object.
 *
 * @param {{ h: number, s: number, v: number }} hsv
 * @returns {string}
 */
export function currentHex(hsv) {
    const rgb = hsvToRgb(hsv.h, hsv.s, hsv.v);
    return rgbToHex(rgb.r, rgb.g, rgb.b);
}
