/**
 * @fileoverview ColorPicker events - centralised drag / pointer / keyboard
 *               event binding for spectrum, hue, alpha, and channel inputs.
 *
 * @module module/ColorPicker/events
 */

import { CLS } from './constants.js';
import razyui from '../../index.js';

// ═══════════════════════════════════════════
//  DRAG HELPER
// ═══════════════════════════════════════════

/**
 * Attach pointer-drag behaviour to an element.
 *
 * Normalises mouse and touch events, clamps coordinates to 0–1,
 * and calls `onMove(x, y)` during drags and `onEnd()` on release.
 *
 * @param {HTMLElement} el       Drag target
 * @param {Function}    onMove   (x: number, y: number) => void
 * @param {Function}    [onEnd]  () => void - called once on release
 * @param {AbortSignal} [signal] - signal for cleanup via AbortController
 */
export function initDrag(el, onMove, onEnd, signal) {
    // Unwrap Elements wrapper to raw DOM element if needed
    const raw = el?.[0] ?? el;
    const $el = razyui(raw);
    const $doc = razyui(document);
    const opts = signal ? { signal } : undefined;
    const pos = (e) => {
        const rect = raw.getBoundingClientRect();
        const cx = e.touches ? e.touches[0].clientX : e.clientX;
        const cy = e.touches ? e.touches[0].clientY : e.clientY;
        return {
            x: Math.max(0, Math.min(1, (cx - rect.left) / rect.width)),
            y: Math.max(0, Math.min(1, (cy - rect.top)  / rect.height)),
        };
    };
    const move = (e) => { e.preventDefault(); const p = pos(e); onMove(p.x, p.y); };
    const up   = ()  => {
        $doc.off('mousemove', move);
        $doc.off('mouseup', up);
        $doc.off('touchmove', move);
        $doc.off('touchend', up);
        if (onEnd) onEnd();
    };
    $el.on('mousedown', (e) => {
        e.preventDefault();
        move(e);
        $doc.on('mousemove', move);
        $doc.on('mouseup', up);
    }, opts);
    $el.on('touchstart', (e) => {
        e.preventDefault();
        move(e);
        $doc.on('touchmove', move, { passive: false });
        $doc.on('touchend', up);
    }, signal ? { passive: false, signal } : { passive: false });
}

// ═══════════════════════════════════════════
//  POPUP outside-click
// ═══════════════════════════════════════════

/**
 * Bind an outside-click listener that closes the popup.
 *
 * @param {HTMLElement} container  Root element
 * @param {Function}    closeFn   () => void
 * @param {Function}    isOpenFn  () => boolean
 * @param {AbortSignal} [signal]  - signal for cleanup via AbortController
 */
export function bindOutsideClick(container, closeFn, isOpenFn, signal) {
    razyui(document).on('mousedown', (e) => {
        if (isOpenFn() && !container.contains(e.target)) closeFn();
    }, signal ? { signal } : undefined);
}

// ═══════════════════════════════════════════
//  PANEL UI EVENTS (tabs, swatches, history, lite footer)
// ═══════════════════════════════════════════

/**
 * Bind panel-level UI events using event delegation where possible.
 *
 * Attaches listeners once on container elements so dynamically
 * re-rendered children (e.g. history chips) are handled automatically.
 *
 * @param {object}      refs       DOM references (all optional)
 * @param {HTMLElement}  [refs.tabs]        Tab button container
 * @param {HTMLElement}  [refs.swatchGrid]  Swatch chip grid
 * @param {HTMLElement}  [refs.clearBtn]    History clear button
 * @param {HTMLElement}  [refs.historyGrid] History chip grid
 * @param {HTMLElement}  [refs.transBtn]    Transparent button (lite mode)
 * @param {HTMLInputElement} [refs.hexInput] Hex input (lite mode)
 * @param {object}      cbs        Callbacks (all optional)
 * @param {Function}    [cbs.onTabSwitch]     (mode: string) => void
 * @param {Function}    [cbs.onSwatchSelect]  (hex: string) => void
 * @param {Function}    [cbs.onClear]         () => void
 * @param {Function}    [cbs.onHistorySelect] (hex: string) => void
 * @param {Function}    [cbs.onTransparent]   () => void
 * @param {Function}    [cbs.onHexChange]     (value: string) => void
 * @param {AbortSignal} [signal]   - signal for cleanup via AbortController
 */
export function bindPanelEvents(refs, cbs, signal) {
    const opts = signal ? { signal } : undefined;

    // 1. Tab switch (delegated on tabs container)
    if (refs.tabs && cbs.onTabSwitch) {
        razyui(refs.tabs).on('click', (e) => {
            const btn = e.target.closest('.' + CLS.TAB);
            if (!btn) return;
            refs.tabs.find('.' + CLS.TAB).each(t =>
                razyui(t).toggleClass(CLS.TAB_ACTIVE, t === btn));
            cbs.onTabSwitch(btn.dataset.mode);
        }, opts);
    }

    // 2. Swatch chip click (delegated on grid)
    if (refs.swatchGrid && cbs.onSwatchSelect) {
        razyui(refs.swatchGrid).on('click', (e) => {
            const chip = e.target.closest('.' + CLS.CHIP);
            if (!chip) return;
            cbs.onSwatchSelect(chip.title);
        }, opts);
    }

    // 3. Clear history button
    if (refs.clearBtn && cbs.onClear) {
        razyui(refs.clearBtn).on('click', cbs.onClear, opts);
    }

    // 4. History chip click (delegated on grid)
    if (refs.historyGrid && cbs.onHistorySelect) {
        razyui(refs.historyGrid).on('click', (e) => {
            const chip = e.target.closest('.' + CLS.CHIP);
            if (!chip) return;
            cbs.onHistorySelect(chip.title);
        }, opts);
    }

    // 5. Transparent button (lite mode)
    if (refs.transBtn && cbs.onTransparent) {
        razyui(refs.transBtn).on('click', cbs.onTransparent, opts);
    }

    // 6. Hex input change (lite mode)
    if (refs.hexInput && cbs.onHexChange) {
        razyui(refs.hexInput).on('change', () => cbs.onHexChange(refs.hexInput.value), opts);
    }
}
