/**
 * @fileoverview ColorPicker class orchestrator.
 *
 * Imports all sub-modules and re-assembles the full ColorPicker class
 * while preserving every public API method and the `getControl()` surface.
 *
 * @module module/ColorPicker/index
 */

import { default as razyui } from '../../index.js';

import { CLS, DEFAULT_SWATCHES, DEFAULTS, PART } from './constants.js';
import * as H                                      from './helpers.js';
import { loadHistory, saveHistory, pushHistory }   from './state.js';
import * as V                                      from './view.js';
import { initDrag, bindPanelEvents } from './events.js';
import { attachOutsideClick } from '../shared/outsideClick.js';
import { positionFloating } from '../shared/positionFloating.js';
import { emitEvent } from '../shared/emitEvent.js';

/**
 * ColorPicker - Full-featured color selector
 *
 * A comprehensive color picker component that supports HSV, HSL, RGB, and HEX color spaces.
 * It provides a 2D color board, hue and alpha sliders, color swatches, and a history of recently used colors.
 *
 * @class ColorPicker
 * @param {string|Element} selector - The DOM selector or element to attach the ColorPicker to.
 * @param {object}   config - Configuration options for the ColorPicker.
 * @param {string}   [config.color='#ff0000']   - Initial color (hex/rgb/hsl).
 * @param {boolean}  [config.showBoard=true]    - Show 2-D color board.
 * @param {boolean}  [config.showAlpha=false]   - Show alpha slider.
 * @param {boolean}  [config.lite=false]        - Lite mode: board + hue only.
 * @param {string}   [config.mode='inline']     - Display mode: 'inline' | 'popup'.
 * @param {boolean}  [config.persistHistory=true] - Save history to localStorage.
 * @param {string}   [config.historyKey]        - localStorage key for history.
 * @param {number}   [config.maxHistory=28]     - Maximum number of history chips.
 * @param {Array}    [config.swatches]          - 2-D array of hex colors for swatches.
 * @param {function} [config.onChange]          - Callback function triggered on color change: (color) => void.
 */
const ColorPicker = class {

    // ═══════════════════════════════════════════
    //  STATIC - colour-space conversions (delegate to helpers)
    // ═══════════════════════════════════════════

    static hsvToRgb(h, s, v)  { return H.hsvToRgb(h, s, v); }
    static rgbToHsv(r, g, b)  { return H.rgbToHsv(r, g, b); }
    static hsvToHsl(h, s, v)  { return H.hsvToHsl(h, s, v); }
    static hslToHsv(h, s, l)  { return H.hslToHsv(h, s, l); }
    static rgbToHex(r, g, b)  { return H.rgbToHex(r, g, b); }
    static hexToRgb(hex)       { return H.hexToRgb(hex); }
    static parseColor(str)     { return H.parseColor(str); }

    static DEFAULT_SWATCHES = DEFAULT_SWATCHES;

    // ═══════════════════════════════════════════
    //  PRIVATE FIELDS
    // ═══════════════════════════════════════════

    #container = null; #config = {};
    #hsv = { h: 0, s: 100, v: 100 }; // internal HSV state
    #alpha = 1;
    #showBoard = true; #showAlpha = false;
    #showSwatches = true; #showHistory = true;
    #lite = false;             // lite mode: board + hue only
    #mode = 'inline';          // 'inline' | 'popup'
    #inputMode = 'hsl';        // active tab: 'hsl' | 'rgb'
    #isOpen = false;

    // History
    #history = []; #persistHistory = true;
    #historyKey = 'rui-color-history'; #maxHistory = 28;
    #swatches = [];

    // DOM refs
    #trigger = null; #panel = null;
    #board = null; #boardCursor = null;
    #hueTrack = null; #hueThumb = null;
    #alphaTrack = null; #alphaGrad = null; #alphaThumb = null;
    #previewCur = null; #previewOld = null; #hexInput = null;
    #hslWrap = null; #rgbWrap = null;
    #chRefs = {};          // { 'hsl-h': {track,thumb,input}, … }
    #tabs = null; #swatchGrid = null; #clearBtn = null; #transBtn = null;
    #historyGrid = null;
    #oldColor = null;      // hex string of the colour when picker opened
    #eventAC = new AbortController();
    #destroyed = false;
    #outsideAC = null;     // AbortController for outside-click (popup cycle mode)
    #hiddenInput = null;

    // ═══════════════════════════════════════════
    //  CONSTRUCTOR
    // ═══════════════════════════════════════════

    constructor(selector, config = {}) {
        const el = razyui(selector);
        if (!el.length) {
            console.warn('ColorPicker: element not found \u2192', selector);
            return;
        }
        this.#container = el[0];
        this.#config   = config;
        this.#showBoard    = config.showBoard ?? DEFAULTS.showBoard;
        this.#showAlpha    = config.showAlpha ?? DEFAULTS.showAlpha;
        this.#showSwatches = config.showSwatches ?? DEFAULTS.showSwatches;
        this.#showHistory  = config.showHistory ?? DEFAULTS.showHistory;
        this.#lite         = config.lite ?? DEFAULTS.lite;
        this.#mode      = config.mode || DEFAULTS.mode;
        this.#persistHistory = config.persistHistory ?? DEFAULTS.persistHistory;
        this.#historyKey = config.historyKey || DEFAULTS.historyKey;
        this.#maxHistory = config.maxHistory || DEFAULTS.maxHistory;
        this.#swatches  = config.swatches || DEFAULT_SWATCHES;
        this.#inputMode = config.defaultMode || DEFAULTS.defaultMode;

        // Parse initial colour
        const initRgb = H.parseColor(config.color || DEFAULTS.color);
        this.#hsv = H.rgbToHsv(initRgb.r, initRgb.g, initRgb.b);
        if (config.alpha !== undefined) this.#alpha = config.alpha;
        this.#oldColor = H.currentHex(this.#hsv);

        this.#history = loadHistory(this.#historyKey, this.#persistHistory);
        this.#init();
        this.#updateAll();

        // Hidden input for native form submission
        if (config.name) {
            const hidden = document.createElement('input');
            hidden.type = 'hidden';
            hidden.name = config.name;
            hidden.value = H.currentHex(this.#hsv);
            this.#container.appendChild(hidden);
            this.#hiddenInput = hidden;
        }
    }

    // ═══════════════════════════════════════════
    //  BUILD DOM
    // ═══════════════════════════════════════════

    #init() {
        const c = this.#container;
        const $c = razyui(c);
        $c.addClass('color-picker ' + CLS.ROOT).html('');
        PART.ROOT.apply($c);

        // Popup trigger
        if (this.#mode === 'popup') {
            $c.addClass(CLS.POPUP);
            this.#trigger = H.mk('button', CLS.TRIGGER);
            this.#trigger.attr('type', 'button');
            PART.TRIGGER.apply(this.#trigger);
            this.#trigger.html(`<span class="${CLS.TRIGGER_SWATCH}"></span><span class="${CLS.TRIGGER_HEX}"></span>`);
            PART.TRIGGER_SWATCH.apply(razyui(this.#trigger).find('.' + CLS.TRIGGER_SWATCH));
            PART.TRIGGER_HEX.apply(razyui(this.#trigger).find('.' + CLS.TRIGGER_HEX));
            $c.append(this.#trigger);
            razyui(this.#trigger).on('click', () => this.toggle(), { signal: this.#eventAC.signal });
        }

        // Panel
        this.#panel = H.mk('div', CLS.PANEL);
        PART.PANEL.apply(this.#panel);
        if (this.#mode === 'popup') {
            this.#panel.addClass(CLS.PANEL_POPUP);
            PART.PANEL_POPUP.apply(this.#panel);
            this.#panel.css('display', 'none');
        }

        if (this.#showBoard)  this.#buildBoard();
        this.#buildHueSlider();
        if (this.#showAlpha) this.#buildAlphaSlider();
        if (!this.#lite) {
            this.#buildInfoRow();
            this.#buildChannels();
            if (this.#showSwatches && this.#swatches.length) this.#buildSwatches();
            if (this.#showHistory) this.#buildHistoryPanel();
        }
        if (this.#lite) this.#buildLiteFooter();
        this.#bindPanelEvents();

        if (this.#mode === 'popup') {
            razyui(document.body).append(this.#panel);
        } else {
            $c.append(this.#panel);
        }
    }

    // ── Board ──

    #buildBoard() {
        const refs = V.buildBoard(this.#panel);
        this.#board = refs.board;
        this.#boardCursor = refs.boardCursor;

        initDrag(this.#board, (x, y) => {
            this.#hsv.s = Math.round(x * 100);
            this.#hsv.v = Math.round((1 - y) * 100);
            this.#updateAll();
            this.#emitChange();
        }, () => this.#pushHistory(), this.#eventAC.signal);
    }

    // ── Hue slider ──

    #buildHueSlider() {
        const refs = V.buildHueSlider(this.#panel);
        this.#hueTrack = refs.hueTrack;
        this.#hueThumb = refs.hueThumb;

        initDrag(this.#hueTrack, (x) => {
            this.#hsv.h = Math.round(x * 360);
            this.#updateAll();
            this.#emitChange();
        }, () => this.#pushHistory(), this.#eventAC.signal);
    }

    // ── Alpha slider ──

    #buildAlphaSlider() {
        const refs = V.buildAlphaSlider(this.#panel);
        this.#alphaTrack = refs.alphaTrack;
        this.#alphaGrad  = refs.alphaGrad;
        this.#alphaThumb = refs.alphaThumb;

        initDrag(this.#alphaTrack, (x) => {
            this.#alpha = Math.round(x * 100) / 100;
            this.#updateAll();
            this.#emitChange();
        }, () => this.#pushHistory(), this.#eventAC.signal);
    }

    // ── Preview + Hex ──

    #buildInfoRow() {
        const refs = V.buildInfoRow(this.#panel);
        this.#previewOld = refs.previewOld;
        this.#previewCur = refs.previewCur;
        this.#hexInput   = refs.hexInput;

        razyui(this.#previewOld).on('click', () => {
            if (this.#oldColor) { this.setColor(this.#oldColor); }
        });

        razyui(this.#hexInput).on('change', () => {
            let v = this.#hexInput.value.trim();
            if (!v.startsWith('#')) v = '#' + v;
            if (/^#([0-9a-fA-F]{3}|[0-9a-fA-F]{6}|[0-9a-fA-F]{8})$/.test(v)) {
                this.setColor(v);
                this.#pushHistory();
            }
        });
    }

    // ── HSL / RGB channel sliders ──

    #buildChannels() {
        const refs = V.buildChannels(
            this.#panel,
            this.#inputMode,
            this.#chRefs,
        );
        this.#tabs    = refs.tabs;
        this.#hslWrap = refs.hslWrap;
        this.#rgbWrap = refs.rgbWrap;

        // Bind drag + input events for every channel
        const bindCh = (group, key, max) => {
            const ref = `${group}-${key}`;
            const r = this.#chRefs[ref]; if (!r) return;
            initDrag(r.track, (x) => {
                const val = Math.round(x * max);
                this.#applyChannel(group, key, val);
            }, () => this.#pushHistory(), this.#eventAC.signal);
            r.input.on('change', () => {
                const val = Math.max(0, Math.min(max, parseInt(r.input.value) || 0));
                this.#applyChannel(group, key, val);
                this.#pushHistory();
            });
        };
        bindCh('hsl', 'h', 360); bindCh('hsl', 's', 100); bindCh('hsl', 'l', 100);
        bindCh('rgb', 'r', 255); bindCh('rgb', 'g', 255); bindCh('rgb', 'b', 255);
    }

    #applyChannel(group, key, val) {
        if (group === 'hsl') {
            const hsl = this.getHSL();
            hsl[key] = val;
            this.#hsv = H.hslToHsv(hsl.h, hsl.s, hsl.l);
        } else {
            const rgb = this.getRGB();
            rgb[key] = val;
            const hsv = H.rgbToHsv(rgb.r, rgb.g, rgb.b);
            if (hsv.s === 0) hsv.h = this.#hsv.h;
            if (hsv.v === 0) { hsv.h = this.#hsv.h; hsv.s = this.#hsv.s; }
            this.#hsv = hsv;
        }
        this.#updateAll();
        this.#emitChange();
    }

    // ── Swatches ──

    #buildSwatches() {
        const refs = V.buildSwatches(this.#panel, this.#swatches);
        this.#swatchGrid = refs.swatchGrid;
    }

    // ── History ──

    #buildHistoryPanel() {
        const refs = V.buildHistoryPanel(this.#panel);
        this.#historyGrid = refs.historyGrid;
        this.#clearBtn    = refs.clearBtn;
        this.#renderHistory();
    }

    #renderHistory() {
        V.renderHistory(this.#historyGrid, this.#history);
    }

    // ── Lite footer ──

    #buildLiteFooter() {
        const refs = V.buildLiteFooter(this.#panel);
        this.#transBtn = refs.transBtn;
        this.#hexInput = refs.hexInput;
    }

    // ── Panel event delegation ──

    #bindPanelEvents() {
        bindPanelEvents(
            {
                tabs:        this.#tabs,
                swatchGrid:  this.#swatchGrid,
                clearBtn:    this.#clearBtn,
                historyGrid: this.#historyGrid,
                transBtn:    this.#transBtn,
                hexInput:    this.#lite ? this.#hexInput : null,
            },
            {
                onTabSwitch: (mode) => {
                    this.#inputMode = mode;
                    this.#hslWrap.css('display', mode === 'hsl' ? '' : 'none');
                    this.#rgbWrap.css('display', mode === 'rgb' ? '' : 'none');
                    V.updateChannels(this.#chRefs, this.#hsv);
                },
                onSwatchSelect: (hex) => {
                    this.setColor(hex);
                    this.#pushHistory();
                },
                onClear: () => this.clearHistory(),
                onHistorySelect: (hex) => this.setColor(hex),
                onTransparent: () => this.#emitTransparent(),
                onHexChange: (value) => {
                    let v = value.trim();
                    if (!v.startsWith('#')) v = '#' + v;
                    if (/^#([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(v)) {
                        this.setColor(v);
                    }
                },
            },
            this.#eventAC.signal,
        );
    }

    // ═══════════════════════════════════════════
    //  UPDATE ALL UI
    // ═══════════════════════════════════════════

    #updateAll() {
        V.updateBoard(this.#board, this.#boardCursor, this.#hsv);
        V.updateHue(this.#hueThumb, this.#hsv);
        if (this.#showAlpha) V.updateAlpha(this.#alphaGrad, this.#alphaThumb, this.#hsv, this.#alpha);
        V.updatePreview(this.#previewCur, this.#previewOld, this.#hsv, this.#alpha, this.#showAlpha, this.#oldColor);
        V.updateHex(this.#hexInput, this.#hsv);
        V.updateChannels(this.#chRefs, this.#hsv);
        if (this.#trigger) V.updateTrigger(this.#trigger, this.#hsv);
    }

    // ═══════════════════════════════════════════
    //  HISTORY (delegated)
    // ═══════════════════════════════════════════

    #pushHistory() {
        const hex = H.currentHex(this.#hsv).toUpperCase();
        pushHistory(this.#history, hex, this.#maxHistory);
        saveHistory(this.#historyKey, this.#history, this.#persistHistory);
        this.#renderHistory();
    }

    // ═══════════════════════════════════════════
    //  HELPERS
    // ═══════════════════════════════════════════

    #emitChange() {
        const color = this.getColor();
        if (this.#hiddenInput) this.#hiddenInput.value = color.hex || '';
        emitEvent(this.#container, 'change', { value: color, color });
        if (typeof this.#config.onChange === 'function') this.#config.onChange(color);
    }

    #emitTransparent() {
        const color = {
            hex: 'transparent', transparent: true, css: 'transparent',
            rgb: null, hsl: null, hsv: null, alpha: 0,
        };
        if (this.#hiddenInput) this.#hiddenInput.value = 'transparent';
        emitEvent(this.#container, 'change', { value: color, color });
        if (typeof this.#config.onChange === 'function') {
            this.#config.onChange(color);
        }
    }

    // ═══════════════════════════════════════════
    //  PUBLIC API
    // ═══════════════════════════════════════════

    /** Get full colour object */
    getColor() {
        const rgb = this.getRGB();
        const hsl = this.getHSL();
        return {
            hex: H.currentHex(this.#hsv),
            rgb, hsl,
            hsv: { ...this.#hsv },
            alpha: this.#alpha,
            css: this.#showAlpha
                ? `rgba(${rgb.r},${rgb.g},${rgb.b},${this.#alpha})`
                : H.currentHex(this.#hsv),
        };
    }

    /** Get RGB */
    getRGB() { return H.hsvToRgb(this.#hsv.h, this.#hsv.s, this.#hsv.v); }
    /** Get HSL */
    getHSL() { return H.hsvToHsl(this.#hsv.h, this.#hsv.s, this.#hsv.v); }
    /** Get hex string */
    getHex() { return H.currentHex(this.#hsv); }

    /** Set colour from any CSS string */
    setColor(str) {
        const rgb = H.parseColor(str);
        const hsv = H.rgbToHsv(rgb.r, rgb.g, rgb.b);
        // Preserve hue for achromatic
        if (hsv.s === 0) hsv.h = this.#hsv.h;
        if (hsv.v === 0) { hsv.h = this.#hsv.h; hsv.s = this.#hsv.s; }
        this.#hsv = hsv;
        this.#updateAll();
        this.#emitChange();
    }

    /** Clear history */
    clearHistory() {
        this.#history = [];
        saveHistory(this.#historyKey, this.#history, this.#persistHistory);
        this.#renderHistory();
    }

    /** Popup open/close */
    open() {
        this.#isOpen = true;
        this.#oldColor = H.currentHex(this.#hsv);

        // Inherit data-theme from nearest themed ancestor
        const themed = this.#container.closest('[data-theme]');
        if (themed) {
            this.#panel[0].setAttribute('data-theme', themed.getAttribute('data-theme'));
        } else {
            this.#panel[0].removeAttribute('data-theme');
        }

        // Show and position
        this.#panel.css('display', 'flex');
        positionFloating(this.#panel[0], this.#trigger[0] || this.#container, {
            strategy: 'fixed',
            gap: 6,
            flip: true,
            width: 'auto',
        });

        V.updatePreview(this.#previewCur, this.#previewOld, this.#hsv, this.#alpha, this.#showAlpha, this.#oldColor);

        // Outside-click (cycle mode — new AC per open)
        this.#outsideAC = attachOutsideClick(
            this.#container, this.#panel[0], () => this.close(),
            { escape: true, guardMs: 60 },
        );
    }
    close() {
        this.#isOpen = false;
        this.#panel.css('display', 'none');
        this.#outsideAC?.abort();
        this.#outsideAC = null;
    }
    toggle() { this.#isOpen ? this.close() : this.open(); }

    setInvalid(invalid) {
        this.#container.classList.toggle(CLS.INVALID, !!invalid);
        this.#container[invalid ? 'setAttribute' : 'removeAttribute']('aria-invalid', 'true');
    }

    focus() { this.#trigger?.[0]?.focus(); }
    blur()  { this.#trigger?.[0]?.blur(); }

    clear() { this.setColor(this.#config.color || '#ff0000'); }

    /** Controller API */
    getControl() {
        const self = this;
        return {
            get value()    { return self.getColor(); },
            set value(v)   { self.setColor(v); },
            get format()   { return self.#config.format || self.#config.mode; },
            set format(v)  { self.#config.format = v; self.#config.mode = v; },
            get name()     { return self.#config.name ?? ''; },
            set name(v)    { self.#config.name = v; if (self.#hiddenInput) self.#hiddenInput.name = v; },
            get required() { return self.#config.required ?? false; },
            set required(v){ self.#config.required = !!v; if (self.#hiddenInput) self.#hiddenInput.required = !!v; self.#container.setAttribute('aria-required', String(!!v)); },
            getColor:     () => self.getColor(),
            setColor:     (c) => self.setColor(c),
            getHex:       () => self.getHex(),
            getRGB:       () => self.getRGB(),
            getHSL:       () => self.getHSL(),
            clearHistory: () => self.clearHistory(),
            open:         () => self.open(),
            close:        () => self.close(),
            toggle:       () => self.toggle(),
            get isOpen()  { return self.isOpen; },
            setInvalid:   (v) => self.setInvalid(v),
            checkValidity:     () => self.#hiddenInput ? self.#hiddenInput.checkValidity() : true,
            reportValidity:    () => self.#hiddenInput ? self.#hiddenInput.reportValidity() : true,
            setCustomValidity: (m) => { if (self.#hiddenInput) self.#hiddenInput.setCustomValidity(m || ''); self.setInvalid(!!m); },
            get label()       { return self.#container.getAttribute('aria-label'); },
            set label(v)      { v ? self.#container.setAttribute('aria-label', v) : self.#container.removeAttribute('aria-label'); },
            get labelledby()  { return self.#container.getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? self.#container.setAttribute('aria-labelledby', v) : self.#container.removeAttribute('aria-labelledby'); },
            get describedby() { return self.#container.getAttribute('aria-describedby'); },
            set describedby(v){ v ? self.#container.setAttribute('aria-describedby', v) : self.#container.removeAttribute('aria-describedby'); },
            focus:        () => self.focus(),
            blur:         () => self.blur(),
            clear:        () => self.clear(),
            destroy:      () => self.destroy(),
            get element() { return self.#container; },
            get destroyed() { return self.#destroyed; },
        };
    }

    /**
     * Teardown - remove panel DOM and clear references.
     */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.close();
        this.#eventAC?.abort();
        this.#outsideAC?.abort();
        this.#outsideAC = null;
        if (this.#hiddenInput) { this.#hiddenInput.remove(); this.#hiddenInput = null; }
        if (this.#panel) {
            this.#panel.remove();
            this.#panel = null;
        }
        this.#container = null;
    }
};

export default ColorPicker;
